PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "remember_token" varchar, "created_at" datetime, "updated_at" datetime, "role" varchar not null default 'user');
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" text not null, "queue" text not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "vpn_users" ("id" integer primary key autoincrement not null, "user_id" integer not null, "name" varchar not null, "status" varchar not null default 'active', "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "servers" ("id" integer primary key autoincrement not null, "hostname" varchar not null, "region" varchar not null, "role" varchar not null, "created_at" datetime, "updated_at" datetime, "last_heartbeat_at" datetime, "cpu_percent" double, "mem_percent" double, "load_1" double, "host" varchar, "ssh_port" integer not null default '22', "ssh_user" varchar not null default 'root', "ssh_password" text, "notes" text);
CREATE TABLE IF NOT EXISTS "exit_nodes" ("id" integer primary key autoincrement not null, "server_id" integer not null, "ip_address" varchar not null, "region" varchar not null, "created_at" datetime, "updated_at" datetime, foreign key("server_id") references "servers"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "products" ("id" integer primary key autoincrement not null, "name" varchar not null, "description" text, "price_cents" integer not null, "currency" varchar not null default 'USD', "duration_days" integer not null default '30', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "orders" ("id" integer primary key autoincrement not null, "user_id" integer not null, "product_id" integer not null, "status" varchar not null, "expires_at" datetime not null, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("product_id") references "products"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "traffic_logs" ("id" integer primary key autoincrement not null, "vpn_user_id" integer not null, "server_id" integer not null, "bytes_up" integer not null default '0', "bytes_down" integer not null default '0', "recorded_at" datetime not null default CURRENT_TIMESTAMP, foreign key("vpn_user_id") references "vpn_users"("id") on delete cascade, foreign key("server_id") references "servers"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "ip_pool" ("id" integer primary key autoincrement not null, "ip_address" varchar not null, "region" varchar not null, "status" varchar not null default 'free', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "resellers" ("id" integer primary key autoincrement not null, "name" varchar not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "agents" ("id" integer primary key autoincrement not null, "reseller_id" integer not null, "name" varchar not null, "created_at" datetime, "updated_at" datetime, foreign key("reseller_id") references "resellers"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "anti_block_policies" ("id" integer primary key autoincrement not null, "server_id" integer not null, "wireguard_obfs" tinyint(1) not null default '0', "tls_camouflage" tinyint(1) not null default '0', "domain_fronting" tinyint(1) not null default '0', "port_rotation" tinyint(1) not null default '0', "custom_profile" text not null default '', foreign key("server_id") references "servers"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "wireguard_peers" ("id" integer primary key autoincrement not null, "vpn_user_id" integer not null, "server_id" integer not null, "public_key" varchar not null, "allowed_ips" varchar not null, "endpoint" varchar not null, "created_at" datetime, "updated_at" datetime, foreign key("vpn_user_id") references "vpn_users"("id") on delete cascade, foreign key("server_id") references "servers"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "client_commands" ("id" integer primary key autoincrement not null, "vpn_user_id" integer not null, "command_type" varchar not null, "payload" text not null default '{}', "created_at" datetime not null default CURRENT_TIMESTAMP, "consumed_at" datetime, foreign key("vpn_user_id") references "vpn_users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "access_exit_routes" ("id" integer primary key autoincrement not null, "access_server_id" integer not null, "exit_node_id" integer not null, "created_at" datetime not null default CURRENT_TIMESTAMP, foreign key("access_server_id") references "servers"("id") on delete cascade, foreign key("exit_node_id") references "exit_nodes"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "server_bandwidth" ("server_id" integer not null, "rate_kbps" integer not null default '0', "updated_at" datetime not null default CURRENT_TIMESTAMP, foreign key("server_id") references "servers"("id") on delete cascade, primary key ("server_id"));
CREATE TABLE IF NOT EXISTS "reseller_api_keys" ("id" integer primary key autoincrement not null, "reseller_id" integer not null, "api_key" varchar not null, "name" varchar not null default '', "created_at" datetime not null default CURRENT_TIMESTAMP, foreign key("reseller_id") references "resellers"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "personal_access_tokens" ("id" integer primary key autoincrement not null, "tokenable_type" varchar not null, "tokenable_id" integer not null, "name" text not null, "token" varchar not null, "abilities" text, "last_used_at" datetime, "expires_at" datetime, "created_at" datetime, "updated_at" datetime);
DELETE FROM sqlite_sequence;
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE INDEX "cache_expiration_index" on "cache" ("expiration");
CREATE INDEX "cache_locks_expiration_index" on "cache_locks" ("expiration");
CREATE INDEX "jobs_queue_reserved_at_available_at_index" on "jobs" ("queue", "reserved_at", "available_at");
CREATE UNIQUE INDEX "failed_jobs_uuid_unique" on "failed_jobs" ("uuid");
CREATE UNIQUE INDEX "servers_hostname_unique" on "servers" ("hostname");
CREATE UNIQUE INDEX "ip_pool_ip_address_unique" on "ip_pool" ("ip_address");
CREATE UNIQUE INDEX "anti_block_policies_server_id_unique" on "anti_block_policies" ("server_id");
CREATE UNIQUE INDEX "wireguard_peers_vpn_user_id_unique" on "wireguard_peers" ("vpn_user_id");
CREATE UNIQUE INDEX "access_exit_routes_access_server_id_unique" on "access_exit_routes" ("access_server_id");
CREATE UNIQUE INDEX "reseller_api_keys_api_key_unique" on "reseller_api_keys" ("api_key");
CREATE INDEX "personal_access_tokens_tokenable_type_tokenable_id_index" on "personal_access_tokens" ("tokenable_type", "tokenable_id");
CREATE UNIQUE INDEX "personal_access_tokens_token_unique" on "personal_access_tokens" ("token");
CREATE INDEX "personal_access_tokens_expires_at_index" on "personal_access_tokens" ("expires_at");
COMMIT;
